<?php namespace App\Http\Middleware; use Closure; use Illuminate\Http\Request; use App\Services\AuditLogService; use Symfony\Component\HttpFoundation\Response; class AuditLogMiddleware { protected $auditLogService; public function __construct(AuditLogService $auditLogService) { $this->auditLogService = $auditLogService; } public function handle(Request $request, Closure $next): Response { $response = $next($request); if ($this->shouldLog($request)) { $this->auditLogService->log( [ 'user_id' => $request->user()?->id, 'method' => $request->method(), 'url' => $request->fullUrl(), 'ip_address' => $request->ip(), 'payload' => $request->except(['password', 'password_confirmation']), 'status_code' => $response->getStatusCode(), ] ); } return $response; } protected function shouldLog(Request $request): bool { $methodsToLog = ['POST', 'PUT', 'PATCH', 'DELETE']; if (!in_array($request->method(), $methodsToLog)) { return false; } $pathsToMonitor = ['/api/v1/cases', '/api/v1/invoices']; foreach ($pathsToMonitor as $path) { if (str_contains($request->getPathInfo(), $path)) { return true; } } return false; } }